<!doctype html><html lang="id"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title><?= e($title) ?></title><link href="https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/css/bootstrap.min.css" rel="stylesheet"><link href="https://cdn.jsdelivr.net/npm/bootstrap-icons/font/bootstrap-icons.css" rel="stylesheet"><link href="https://fonts.googleapis.com/css2?family=Nunito:wght@400;700;800;900&display=swap" rel="stylesheet"><link href="<?= baseUrl('assets/css/style.css') ?>" rel="stylesheet"></head><body><main class="admin-main min-vh-100 p-4 p-lg-5"><div class="container" style="max-width:900px"><a class="btn btn-outline-paw mb-3" href="index.php?page=admin&section=bookings"><i class="bi bi-arrow-left"></i> Kembali</a><form class="form-card p-4" method="post" enctype="multipart/form-data" action="index.php?page=admin&section=bookings&action=create"><?= csrfField() ?><h1 class="section-title mb-4">Tambah Booking Manual</h1><div class="row g-3"><div class="col-md-6"><label class="form-label fw-bold">Nama Pemilik</label><select name="user_id" class="form-select" required><?php foreach ($users as $u): ?><option value="<?= (int) $u['id'] ?>"><?= e($u['name']) ?> - <?= e($u['email']) ?></option><?php endforeach; ?></select></div><div class="col-md-6"><label class="form-label fw-bold">Layanan</label><select name="service_id" class="form-select" required><?php foreach ($services as $s): ?><option value="<?= (int) $s['id'] ?>"><?= e($s['name']) ?> - <?= rupiah($s['price']) ?></option><?php endforeach; ?></select></div><div class="col-md-6"><label class="form-label fw-bold">Nama Hewan</label><input name="pet_name" class="form-control" required></div><div class="col-md-6"><label class="form-label fw-bold">Jenis Hewan</label><select name="pet_type" class="form-select" required><option>Kucing</option><option>Anjing</option></select></div><div class="col-md-4"><label class="form-label fw-bold">Tanggal</label><input type="date" name="booking_date" class="form-control" required></div><div class="col-md-4"><label class="form-label fw-bold">Jam</label><input type="time" name="booking_time" min="08:00" max="17:00" class="form-control" required></div><div class="col-md-4"><label class="form-label fw-bold">Status</label><select name="status" class="form-select"><?php foreach (['pending','confirmed','processing','completed','cancelled'] as $st): ?><option value="<?= $st ?>"><?= ucfirst($st) ?></option><?php endforeach; ?></select></div><div class="col-12"><label class="form-label fw-bold">Catatan</label><textarea name="notes" rows="3" class="form-control"></textarea></div><div class="col-12"><label class="form-label fw-bold">Foto Hewan</label><input type="file" name="pet_image" class="form-control image-input" accept=".jpg,.jpeg,.png" data-preview="#petPreview" required><img id="petPreview" class="table-thumb d-none mt-3" alt="Preview"></div></div><button class="btn btn-primary-paw mt-4">Simpan Booking</button></form></div></main><script src="<?= baseUrl('assets/js/main.js') ?>"></script></body></html>
